import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  if (parsed != null && parsed > 0) return parsed;
  if (currentValue != null && currentValue > 0) return currentValue;
  return fallback;
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/features/export/custom_export_dimensions.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

enum ExportAction {
  saveOnly,
  saveAndShare,
}

class ExportSheetSubmission {
  final ExportOptions options;
  final ExportAction action;

  const ExportSheetSubmission({
    required this.options,
    required this.action,
  });
}

/// A bottom sheet for configuring export options
class ExportOptionsSheet extends StatefulWidget {
  final ExportOptions initialOptions;
  final String fractalType;

  const ExportOptionsSheet({
    Key? key,
    required this.initialOptions,
    required this.fractalType,
  }) : super(key: key);

  static Future<ExportSheetSubmission?> show(
    BuildContext context, {
    required ExportOptions initialOptions,
    required String fractalType,
  }) {
    return showModalBottomSheet<ExportSheetSubmission>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (_) => ExportOptionsSheet(
        initialOptions: initialOptions,
        fractalType: fractalType,
      ),
    );
  }

  @override
  State<ExportOptionsSheet> createState() => _ExportOptionsSheetState();
}

class _ExportOptionsSheetState extends State<ExportOptionsSheet> {
  late ExportOptions _options;
  late TextEditingController _customWidthController;
  late TextEditingController _customHeightController;
  bool _showAdvanced = false;
  bool _showCustomization = false;

  @override
  void initState() {
    super.initState();
    _options = widget.initialOptions;
    _customWidthController = TextEditingController(
      text: _options.customWidth?.toString() ??
          defaultCustomExportWidth.toString(),
    );
    _customHeightController = TextEditingController(
      text: _options.customHeight?.toString() ??
          defaultCustomExportHeight.toString(),
    );

    // Keep custom fields and option values in sync so summary/export payloads
    // match what the user sees, even before they edit the text fields.
    if (_options.resolution == ExportResolution.custom) {
      _options = _effectiveOptionsForExport();
    }
  }

  @override
  void dispose() {
    _customWidthController.dispose();
    _customHeightController.dispose();
    super.dispose();
  }

  ExportOptions _optionsWithCustomFields() {
    return withResolvedCustomExportDimensions(
      options: _options,
      widthText: _customWidthController.text,
      heightText: _customHeightController.text,
    );
  }

  ExportOptions _effectiveOptionsForExport() {
    if (_options.resolution != ExportResolution.custom) {
      return _options;
    }

    return _optionsWithCustomFields();
  }

  @override
  Widget build(BuildContext context) {
    final l10n = AppLocalizations.of(context)!;
    final theme = Theme.of(context);

    return DraggableScrollableSheet(
      initialChildSize: 0.7,
      minChildSize: 0.5,
      maxChildSize: 0.95,
      expand: false,
      builder: (context, scrollController) {
        return Container(
          decoration: BoxDecoration(
            color: theme.colorScheme.surface,
            borderRadius: const BorderRadius.vertical(top: Radius.circular(20)),
          ),
          child: Column(
            children: [
              // Handle bar
              Container(
                margin: const EdgeInsets.symmetric(vertical: 12),
                width: 40,
                height: 4,
                decoration: BoxDecoration(
                  color: theme.colorScheme.onSurface.withValues(alpha: 0.3),
                  borderRadius: BorderRadius.circular(2),
                ),
              ),

              // Title
              Padding(
                padding: const EdgeInsets.symmetric(horizontal: 16),
                child: Row(
                  children: [
                    Icon(Icons.share_rounded, color: theme.colorScheme.primary),
                    const SizedBox(width: 12),
                    Text(
                      l10n.exportTitle,
                      style: theme.textTheme.headlineSmall?.copyWith(
                        fontWeight: FontWeight.bold,
                      ),
                    ),
                  ],
                ),
              ),

              const SizedBox(height: 12),

              // Content
              Expanded(
                child: ListView(
                  controller: scrollController,
                  padding: const EdgeInsets.symmetric(horizontal: 16),
                  children: [
                    _buildSimpleModeCard(context, l10n),

                    const SizedBox(height: 12),

                    // Keep quick presets always visible for easy one-tap changes.
                    _buildQuickPresets(context, l10n),

                    if (_showCustomization) ...[
                      const SizedBox(height: 16),

                      // Format selection
                      _buildFormatSection(context, l10n),

                      const SizedBox(height: 16),

                      // Resolution selection
                      _buildResolutionSection(context, l10n),

                      const SizedBox(height: 16),

                      // Quality slider (for JPG/WebP)
                      if (_options.format != ExportFormat.png)
                        _buildQualitySection(context, l10n),

                      // Advanced options toggle
                      _buildAdvancedToggle(context, l10n),

                      if (_showAdvanced) ...[
                        const SizedBox(height: 12),
                        _buildAdvancedOptions(context, l10n),
                      ],
                    ],

                    const SizedBox(height: 24),

                    // Export info summary
                    _buildExportSummary(context, l10n),

                    const SizedBox(height: 100), // Space for button
                  ],
                ),
              ),

              // Export actions
              _buildExportActions(context, l10n),
            ],
          ),
        );
      },
    );
  }

  Widget _buildSimpleModeCard(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);

    return Container(
      padding: const EdgeInsets.all(14),
      decoration: BoxDecoration(
        color:
            theme.colorScheme.surfaceContainerHighest.withValues(alpha: 0.45),
        borderRadius: BorderRadius.circular(12),
        border: Border.all(
          color: theme.colorScheme.outline.withValues(alpha: 0.25),
        ),
      ),
      child: Row(
        children: [
          Icon(Icons.flash_on_rounded, color: theme.colorScheme.primary),
          const SizedBox(width: 10),
          Expanded(
            child: Text(
              _showCustomization
                  ? l10n.exportCustomizeModeHint
                  : l10n.exportSimpleModeHint,
              style: theme.textTheme.bodySmall,
            ),
          ),
          const SizedBox(width: 8),
          TextButton(
            onPressed: () {
              setState(() {
                _showCustomization = !_showCustomization;
                if (!_showCustomization) {
                  _showAdvanced = false;
                }
              });
            },
            child: Text(_showCustomization
                ? l10n.exportButtonSimple
                : l10n.exportButtonCustomize),
          ),
        ],
      ),
    );
  }

  Widget _buildQuickPresets(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          l10n.exportQuickPresets,
          style: theme.textTheme.titleSmall?.copyWith(
            color: theme.colorScheme.onSurface.withValues(alpha: 0.7),
          ),
        ),
        const SizedBox(height: 12),
        SingleChildScrollView(
          scrollDirection: Axis.horizontal,
          child: Row(
            children: [
              _QuickPresetChip(
                icon: Icons.share,
                label: l10n.exportPresetSocial,
                isSelected: _options == ExportPresets.socialShare,
                onTap: () =>
                    setState(() => _options = ExportPresets.socialShare),
              ),
              const SizedBox(width: 8),
              _QuickPresetChip(
                icon: Icons.high_quality,
                label: l10n.exportPresetHighQuality,
                isSelected: _options == ExportPresets.highQualityPng,
                onTap: () =>
                    setState(() => _options = ExportPresets.highQualityPng),
              ),
              const SizedBox(width: 8),
              _QuickPresetChip(
                icon: Icons.web,
                label: l10n.exportPresetWeb,
                isSelected: _options == ExportPresets.webOptimized,
                onTap: () =>
                    setState(() => _options = ExportPresets.webOptimized),
              ),
              const SizedBox(width: 8),
              _QuickPresetChip(
                icon: Icons.layers,
                label: l10n.exportPresetTransparent,
                isSelected: _options == ExportPresets.transparentOverlay,
                onTap: () =>
                    setState(() => _options = ExportPresets.transparentOverlay),
              ),
            ],
          ),
        ),
      ],
    );
  }

  Widget _buildFormatSection(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          l10n.exportFormat,
          style: theme.textTheme.titleSmall?.copyWith(
            color: theme.colorScheme.onSurface.withValues(alpha: 0.7),
          ),
        ),
        const SizedBox(height: 12),
        SegmentedButton<ExportFormat>(
          segments: [
            ButtonSegment(
              value: ExportFormat.png,
              label: Text(l10n.exportFormatPng),
              icon: const Icon(Icons.image),
            ),
            ButtonSegment(
              value: ExportFormat.jpg,
              label: Text(l10n.exportFormatJpg),
              icon: const Icon(Icons.photo),
            ),
            ButtonSegment(
              value: ExportFormat.webp,
              label: Text(l10n.exportFormatWebp),
              icon: const Icon(Icons.web_asset),
            ),
          ],
          selected: {_options.format},
          onSelectionChanged: (selected) {
            setState(() {
              _options = _options.copyWith(
                format: selected.first,
                // Auto-disable transparency for JPG
                transparentBackground: selected.first == ExportFormat.jpg
                    ? false
                    : _options.transparentBackground,
              );
            });
          },
        ),
        const SizedBox(height: 8),
        _buildFormatHint(context, l10n),
      ],
    );
  }

  Widget _buildFormatHint(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);
    String hint;

    switch (_options.format) {
      case ExportFormat.png:
        hint = l10n.exportFormatHintPng;
        break;
      case ExportFormat.jpg:
        hint = l10n.exportFormatHintJpg;
        break;
      case ExportFormat.webp:
        hint = l10n.exportFormatHintWebp;
        break;
    }

    return Text(
      hint,
      style: theme.textTheme.bodySmall?.copyWith(
        color: theme.colorScheme.onSurface.withValues(alpha: 0.5),
      ),
    );
  }

  Widget _buildResolutionSection(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          l10n.exportResolution,
          style: theme.textTheme.titleSmall?.copyWith(
            color: theme.colorScheme.onSurface.withValues(alpha: 0.7),
          ),
        ),
        const SizedBox(height: 12),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: ExportResolution.values.map((resolution) {
            return ChoiceChip(
              label: Text(resolution.displayName),
              selected: _options.resolution == resolution,
              onSelected: (selected) {
                if (selected) {
                  setState(() {
                    if (resolution == ExportResolution.custom) {
                      _options = _optionsWithCustomFields().copyWith(
                        resolution: ExportResolution.custom,
                      );
                    } else {
                      _options = _options.copyWith(resolution: resolution);
                    }
                  });
                }
              },
            );
          }).toList(),
        ),
        if (_options.resolution == ExportResolution.custom) ...[
          const SizedBox(height: 16),
          Row(
            children: [
              Expanded(
                child: TextField(
                  controller: _customWidthController,
                  decoration: InputDecoration(
                    labelText: l10n.exportWidth,
                    suffixText: 'px',
                    border: const OutlineInputBorder(),
                  ),
                  keyboardType: TextInputType.number,
                  onChanged: (value) {
                    final width = int.tryParse(value);
                    if (width != null && width > 0) {
                      setState(() {
                        _options = _options.copyWith(customWidth: width);
                      });
                    }
                  },
                ),
              ),
              const SizedBox(width: 12),
              const Icon(Icons.close, size: 16),
              const SizedBox(width: 12),
              Expanded(
                child: TextField(
                  controller: _customHeightController,
                  decoration: InputDecoration(
                    labelText: l10n.exportHeight,
                    suffixText: 'px',
                    border: const OutlineInputBorder(),
                  ),
                  keyboardType: TextInputType.number,
                  onChanged: (value) {
                    final height = int.tryParse(value);
                    if (height != null && height > 0) {
                      setState(() {
                        _options = _options.copyWith(customHeight: height);
                      });
                    }
                  },
                ),
              ),
            ],
          ),
        ],
      ],
    );
  }

  Widget _buildQualitySection(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          mainAxisAlignment: MainAxisAlignment.spaceBetween,
          children: [
            Text(
              l10n.exportQuality,
              style: theme.textTheme.titleSmall?.copyWith(
                color: theme.colorScheme.onSurface.withValues(alpha: 0.7),
              ),
            ),
            Text(
              '${_options.quality}%',
              style: theme.textTheme.titleSmall?.copyWith(
                color: theme.colorScheme.primary,
                fontWeight: FontWeight.bold,
              ),
            ),
          ],
        ),
        Slider(
          value: _options.quality.toDouble(),
          min: 50,
          max: 100,
          divisions: 10,
          label: '${_options.quality}%',
          onChanged: (value) {
            setState(() {
              _options = _options.copyWith(quality: value.round());
            });
          },
        ),
        const SizedBox(height: 8),
      ],
    );
  }

  Widget _buildAdvancedToggle(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);

    return InkWell(
      onTap: () => setState(() => _showAdvanced = !_showAdvanced),
      borderRadius: BorderRadius.circular(8),
      child: Padding(
        padding: const EdgeInsets.symmetric(vertical: 8),
        child: Row(
          children: [
            Text(
              l10n.exportAdvancedOptions,
              style: theme.textTheme.titleSmall?.copyWith(
                color: theme.colorScheme.onSurface.withValues(alpha: 0.7),
              ),
            ),
            const Spacer(),
            Icon(
              _showAdvanced ? Icons.expand_less : Icons.expand_more,
              color: theme.colorScheme.onSurface.withValues(alpha: 0.5),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildAdvancedOptions(BuildContext context, AppLocalizations l10n) {
    return Column(
      children: [
        // Transparent background (only for PNG/WebP)
        if (_options.format != ExportFormat.jpg)
          SwitchListTile(
            title: Text(l10n.exportTransparentBg),
            subtitle: Text(l10n.exportTransparentBgHint),
            value: _options.transparentBackground,
            onChanged: (value) {
              setState(() {
                _options = _options.copyWith(transparentBackground: value);
              });
            },
          ),

        // Embed metadata
        SwitchListTile(
          title: Text(l10n.exportEmbedMetadata),
          subtitle: Text(l10n.exportEmbedMetadataHint),
          value: _options.embedMetadata,
          onChanged: (value) {
            setState(() {
              _options = _options.copyWith(embedMetadata: value);
            });
          },
        ),
      ],
    );
  }

  Widget _buildExportSummary(BuildContext context, AppLocalizations l10n) {
    final theme = Theme.of(context);
    final effectiveOptions = _effectiveOptionsForExport();
    final dims = effectiveOptions.resolution.dimensions;

    String resolutionText;
    if (effectiveOptions.resolution == ExportResolution.custom) {
      final w = effectiveOptions.customWidth ?? defaultCustomExportWidth;
      final h = effectiveOptions.customHeight ?? defaultCustomExportHeight;
      resolutionText = '$w×$h';
    } else if (dims != null) {
      resolutionText = '${dims.$1}×${dims.$2}';
    } else {
      resolutionText = l10n.exportScreenResolution;
    }

    return Container(
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: theme.colorScheme.surfaceContainerHighest.withValues(alpha: 0.5),
        borderRadius: BorderRadius.circular(12),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text(
            l10n.exportSummary,
            style: theme.textTheme.titleSmall?.copyWith(
              fontWeight: FontWeight.bold,
            ),
          ),
          const SizedBox(height: 12),
          _SummaryRow(
            icon: Icons.photo_size_select_large,
            label: l10n.exportResolution,
            value: resolutionText,
          ),
          const SizedBox(height: 8),
          _SummaryRow(
            icon: Icons.image,
            label: l10n.exportFormat,
            value: effectiveOptions.format.displayName,
          ),
          if (effectiveOptions.format != ExportFormat.png) ...[
            const SizedBox(height: 8),
            _SummaryRow(
              icon: Icons.tune,
              label: l10n.exportQuality,
              value: '${effectiveOptions.quality}%',
            ),
          ],
          if (effectiveOptions.transparentBackground) ...[
            const SizedBox(height: 8),
            _SummaryRow(
              icon: Icons.layers,
              label: l10n.exportTransparentBg,
              value: '✓',
            ),
          ],
          if (effectiveOptions.embedMetadata) ...[
            const SizedBox(height: 8),
            _SummaryRow(
              icon: Icons.info_outline,
              label: l10n.exportEmbedMetadata,
              value: '✓',
            ),
          ],
        ],
      ),
    );
  }

  Widget _buildExportActions(BuildContext context, AppLocalizations l10n) {
    final effectiveOptions = _effectiveOptionsForExport();

    return Container(
      padding: const EdgeInsets.all(20),
      decoration: BoxDecoration(
        color: Theme.of(context).colorScheme.surface,
        boxShadow: [
          BoxShadow(
            color: Colors.black.withValues(alpha: 0.1),
            blurRadius: 8,
            offset: const Offset(0, -2),
          ),
        ],
      ),
      child: SafeArea(
        child: Row(
          children: [
            Expanded(
              child: OutlinedButton.icon(
                key: const ValueKey('exportSaveButton'),
                onPressed: () {
                  Navigator.of(context).pop(
                    ExportSheetSubmission(
                      options: effectiveOptions,
                      action: ExportAction.saveOnly,
                    ),
                  );
                },
                icon: const Icon(Icons.save_alt_rounded),
                label: Text(l10n.exportNow),
                style: OutlinedButton.styleFrom(
                  padding: const EdgeInsets.symmetric(vertical: 16),
                ),
              ),
            ),
            const SizedBox(width: 12),
            Expanded(
              child: FilledButton.icon(
                key: const ValueKey('exportShareButton'),
                onPressed: () {
                  Navigator.of(context).pop(
                    ExportSheetSubmission(
                      options: effectiveOptions,
                      action: ExportAction.saveAndShare,
                    ),
                  );
                },
                icon: const Icon(Icons.share_rounded),
                label: Text(l10n.share),
                style: FilledButton.styleFrom(
                  padding: const EdgeInsets.symmetric(vertical: 16),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

class _QuickPresetChip extends StatelessWidget {
  final IconData icon;
  final String label;
  final bool isSelected;
  final VoidCallback onTap;

  const _QuickPresetChip({
    required this.icon,
    required this.label,
    required this.isSelected,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Semantics(
      button: true,
      selected: isSelected,
      label: isSelected
          ? '$label export preset, selected'
          : '$label export preset',
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(12),
        child: ConstrainedBox(
          constraints: const BoxConstraints(minHeight: 48),
          child: Container(
            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
            decoration: BoxDecoration(
              color: isSelected
                  ? theme.colorScheme.primaryContainer
                  : theme.colorScheme.surfaceContainerHighest,
              borderRadius: BorderRadius.circular(12),
              border: isSelected
                  ? Border.all(color: theme.colorScheme.primary, width: 2)
                  : null,
            ),
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                Icon(
                  icon,
                  size: 18,
                  color: isSelected
                      ? theme.colorScheme.primary
                      : theme.colorScheme.onSurface.withValues(alpha: 0.7),
                ),
                const SizedBox(width: 8),
                Text(
                  label,
                  style: theme.textTheme.bodyMedium?.copyWith(
                    color: isSelected
                        ? theme.colorScheme.primary
                        : theme.colorScheme.onSurface.withValues(alpha: 0.7),
                    fontWeight:
                        isSelected ? FontWeight.bold : FontWeight.normal,
                  ),
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

class _SummaryRow extends StatelessWidget {
  final IconData icon;
  final String label;
  final String value;

  const _SummaryRow({
    required this.icon,
    required this.label,
    required this.value,
  });

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Row(
      children: [
        Icon(
          icon,
          size: 16,
          color: theme.colorScheme.onSurface.withValues(alpha: 0.5),
        ),
        const SizedBox(width: 8),
        Text(
          label,
          style: theme.textTheme.bodySmall?.copyWith(
            color: theme.colorScheme.onSurface.withValues(alpha: 0.7),
          ),
        ),
        const Spacer(),
        Text(
          value,
          style: theme.textTheme.bodySmall?.copyWith(
            fontWeight: FontWeight.bold,
          ),
        ),
      ],
    );
  }
}

import 'package:flutter/material.dart';

import 'package:flutter_fractals/core/models/video_export_options.dart';
import 'package:flutter_fractals/core/theme/app_theme.dart';

/// Minimal UI scaffold for video export.
///
/// The app's video export pipeline lives in [VideoExportService]. This sheet
/// intentionally stays lightweight so the viewer can launch it without build
/// errors even when advanced UI is still evolving.
class VideoExportSheet extends StatelessWidget {
  final VideoExportOptions initialOptions;
  final String fractalType;
  final List<String> availableParameters;
  final Map<String, (double, double)> parameterRanges;
  final ValueChanged<VideoExportOptions> onExport;

  const VideoExportSheet({
    super.key,
    required this.initialOptions,
    required this.fractalType,
    required this.availableParameters,
    required this.parameterRanges,
    required this.onExport,
  });

  @override
  Widget build(BuildContext context) {
    return Container(
      constraints: BoxConstraints(
        maxHeight: MediaQuery.of(context).size.height * 0.85,
      ),
      decoration: BoxDecoration(
        color: AppColors.surface,
        borderRadius: const BorderRadius.vertical(top: Radius.circular(24)),
      ),
      child: Padding(
        padding: const EdgeInsets.all(AppSpacing.xl),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Expanded(
                  child: Text('Export Video', style: AppTypography.headlineMedium),
                ),
                IconButton(
                  tooltip: MaterialLocalizations.of(context).closeButtonTooltip,
                  onPressed: () => Navigator.of(context).pop(),
                  icon: const Icon(Icons.close_rounded),
                ),
              ],
            ),
            const SizedBox(height: AppSpacing.sm),
            Text(
              'Video export UI is scaffolded. Tap Export to run with default options.',
              style: AppTypography.bodyMedium.copyWith(color: AppColors.textMuted),
            ),
            const SizedBox(height: AppSpacing.lg),
            SizedBox(
              width: double.infinity,
              child: ElevatedButton.icon(
                onPressed: () {
                  Navigator.of(context).pop();
                  onExport(initialOptions);
                },
                icon: const Icon(Icons.movie_creation_outlined),
                label: const Text('Export'),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

import 'dart:io';

import 'package:flutter/foundation.dart' show kIsWeb;
import 'package:flutter/material.dart';
import 'package:provider/provider.dart';

import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/services/batch_export_service.dart';
import 'package:flutter_fractals/core/services/preset_store.dart';
import 'package:flutter_fractals/core/theme/app_theme.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

class BatchExportDialog extends StatefulWidget {
  final GlobalKey boundaryKey;

  const BatchExportDialog({
    super.key,
    required this.boundaryKey,
  });

  @override
  State<BatchExportDialog> createState() => _BatchExportDialogState();
}

class _BatchExportDialogState extends State<BatchExportDialog> {
  final _service = const BatchExportService();

  bool _running = true;
  bool _cancelled = false;
  double _progress = 0;
  String _status = '';
  Directory? _outDir;
  File? _contactSheet;
  final List<BatchExportItemResult> _items = [];
  Object? _error;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) => _run());
  }

  Future<void> _run() async {
    if (kIsWeb) {
      setState(() {
        _running = false;
        _error = UnsupportedError('Batch export is not supported on web');
      });
      return;
    }
    final controller = context.read<FractalController>();
    final presetStore = context.read<PresetStore>();
    final l10n = AppLocalizations.of(context)!;

    final initialModule = controller.module;
    final initialParams = Map<String, Object>.from(controller.params);
    final initialView = controller.view;
    final initialTransparent = controller.transparentBackground;

    setState(() {
      _status = l10n.batchExportPreparing;
    });

    try {
      final builtIn = controller.module.builtInPresets;
      final user = await presetStore.loadUserPresets(controller.module.id);
      final presets = <FractalPreset>[...builtIn, ...user];

      if (presets.isEmpty) {
        setState(() {
          _running = false;
          _status = l10n.batchExportNoPresets;
        });
        return;
      }

      const options = ExportOptions(
        format: ExportFormat.png,
        resolution: ExportResolution.fullHd,
        embedMetadata: true,
      );

      controller.setTransparentBackground(options.transparentBackground);

      final size = MediaQuery.of(context).size;

      final result = await _service.exportPresets(
        boundaryKey: widget.boundaryKey,
        applyPreset: (preset) async {
          if (preset.moduleId != controller.module.id) return;
          controller.applyPreset(preset);
        },
        presets: presets,
        options: options,
        screenWidth: size.width,
        screenHeight: size.height,
        moduleId: controller.module.id,
        moduleDisplayName: controller.module.displayName(l10n),
        currentParameters: () => controller.params,
        onProgress: (p, status) {
          if (!mounted) return;
          setState(() {
            _progress = p;
            _status = status;
          });
        },
        onItemDone: (item) {
          if (!mounted) return;
          setState(() {
            _items.add(item);
          });
        },
        isCancelled: () => _cancelled,
      );

      if (!mounted) return;
      setState(() {
        _outDir = result.directory;
        _contactSheet = result.contactSheet;
        _running = false;
        _status = _cancelled ? l10n.batchExportCancelled : l10n.batchExportDone;
        _progress = 1.0;
      });
    } catch (e) {
      if (!mounted) return;
      setState(() {
        _error = e;
        _running = false;
      });
    } finally {
      controller.loadState(
        module: initialModule,
        params: initialParams,
        view: initialView,
        transparentBackground: initialTransparent,
        animateModule: false,
      );
    }
  }

  void _cancelOrClose() {
    final l10n = AppLocalizations.of(context)!;
    if (!_running) {
      Navigator.of(context).pop();
      return;
    }

    setState(() {
      _cancelled = true;
      _status = l10n.batchExportCancelling;
    });
  }

  @override
  Widget build(BuildContext context) {
    final l10n = AppLocalizations.of(context)!;

    return Dialog.fullscreen(
      backgroundColor: AppColors.background,
      child: SafeArea(
        child: Column(
          children: [
            Padding(
              padding: const EdgeInsets.fromLTRB(
                AppSpacing.lg,
                AppSpacing.lg,
                AppSpacing.lg,
                AppSpacing.md,
              ),
              child: Row(
                children: [
                  Expanded(
                    child: Text(
                      l10n.batchExportTitle,
                      style: AppTypography.headlineSmall,
                    ),
                  ),
                  TextButton(
                    onPressed: _cancelOrClose,
                    child: Text(_running ? l10n.batchExportCancel : l10n.actionClose),
                  ),
                ],
              ),
            ),
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: AppSpacing.lg),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    _status,
                    style: AppTypography.bodyMedium.copyWith(
                      color: AppColors.textSecondary,
                    ),
                  ),
                  const SizedBox(height: AppSpacing.sm),
                  LinearProgressIndicator(
                    value: _running ? _progress.clamp(0.0, 1.0) : 1.0,
                    backgroundColor: AppColors.surfaceVariant,
                    color: AppColors.primary,
                    minHeight: 6,
                    borderRadius: BorderRadius.circular(6),
                  ),
                ],
              ),
            ),
            const SizedBox(height: AppSpacing.lg),
            if (_error != null)
              Padding(
                padding: const EdgeInsets.all(AppSpacing.lg),
                child: Container(
                  padding: const EdgeInsets.all(AppSpacing.lg),
                  decoration: BoxDecoration(
                    color: AppColors.error.withValues(alpha: 0.08),
                    borderRadius: BorderRadius.circular(12),
                    border: Border.all(color: AppColors.error.withValues(alpha: 0.3)),
                  ),
                  child: Row(
                    children: [
                      const Icon(Icons.error_outline_rounded, color: AppColors.error),
                      const SizedBox(width: AppSpacing.md),
                      Expanded(
                        child: Text(
                          l10n.exportFailed(_error.toString()),
                          style: AppTypography.bodySmall.copyWith(color: AppColors.error),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            Expanded(
              child: _items.isEmpty
                  ? Center(
                      child: Text(
                        _running ? l10n.batchExportPreparing : l10n.batchExportDone,
                        style: AppTypography.bodyMedium.copyWith(
                          color: AppColors.textMuted,
                        ),
                      ),
                    )
                  : Padding(
                      padding: const EdgeInsets.symmetric(horizontal: AppSpacing.lg),
                      child: GridView.builder(
                        gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
                          crossAxisCount: 3,
                          crossAxisSpacing: 12,
                          mainAxisSpacing: 12,
                        ),
                        itemCount: _items.length,
                        itemBuilder: (context, index) {
                          final item = _items[index];
                          return _ExportThumbTile(
                            name: item.preset.name,
                            file: item.file,
                          );
                        },
                      ),
                    ),
            ),
            if (!_running && _outDir != null)
              Padding(
                padding: const EdgeInsets.fromLTRB(
                  AppSpacing.lg,
                  AppSpacing.md,
                  AppSpacing.lg,
                  AppSpacing.lg,
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      '${l10n.batchExportSavedTo} ${_outDir!.path}',
                      style: AppTypography.bodySmall.copyWith(color: AppColors.textMuted),
                    ),
                    if (_contactSheet != null)
                      Padding(
                        padding: const EdgeInsets.only(top: AppSpacing.xs),
                        child: Text(
                          '${l10n.batchExportContactSheet}: ${_contactSheet!.path}',
                          style: AppTypography.bodySmall.copyWith(color: AppColors.textMuted),
                        ),
                      ),
                  ],
                ),
              ),
          ],
        ),
      ),
    );
  }
}

class _ExportThumbTile extends StatelessWidget {
  final String name;
  final File file;

  const _ExportThumbTile({
    required this.name,
    required this.file,
  });

  @override
  Widget build(BuildContext context) {
    return ClipRRect(
      borderRadius: BorderRadius.circular(12),
      child: Container(
        decoration: BoxDecoration(
          color: AppColors.surface,
          border: Border.all(color: AppColors.border.withValues(alpha: 0.35)),
        ),
        child: Stack(
          fit: StackFit.expand,
          children: [
            Image.file(file, fit: BoxFit.cover),
            Positioned(
              left: 0,
              right: 0,
              bottom: 0,
              child: Container(
                padding: const EdgeInsets.all(8),
                decoration: BoxDecoration(
                  gradient: LinearGradient(
                    begin: Alignment.topCenter,
                    end: Alignment.bottomCenter,
                    colors: [
                      Colors.transparent,
                      Colors.black.withValues(alpha: 0.75),
