                child: Text(
                  name,
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                  style: AppTypography.labelSmall.copyWith(color: Colors.white),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/features/export/export_options_sheet.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';
import 'package:flutter_test/flutter_test.dart';

class _SheetHarness {
  ExportSheetSubmission? submission;
}

void main() {
  Future<_SheetHarness> pumpSheet(
    WidgetTester tester, {
    ExportOptions initialOptions = const ExportOptions(),
  }) async {
    final harness = _SheetHarness();
    await tester.pumpWidget(
      MaterialApp(
        locale: const Locale('en'),
        localizationsDelegates: AppLocalizations.localizationsDelegates,
        supportedLocales: AppLocalizations.supportedLocales,
        home: Scaffold(
          body: Builder(
            builder: (context) => Center(
              child: ElevatedButton(
                onPressed: () async {
                  harness.submission = await ExportOptionsSheet.show(
                    context,
                    initialOptions: initialOptions,
                    fractalType: 'mandelbrot',
                  );
                },
                child: const Text('Open'),
              ),
            ),
          ),
        ),
      ),
    );
    await tester.tap(find.text('Open'));
    await tester.pumpAndSettle();
    return harness;
  }

  Future<ExportSheetSubmission?> pumpSheetAndSubmit(
    WidgetTester tester, {
    required Finder submitButton,
    ExportOptions initialOptions = const ExportOptions(),
  }) async {
    final harness = await pumpSheet(
      tester,
      initialOptions: initialOptions,
    );
    await tester.tap(submitButton);
    await tester.pumpAndSettle();
    return harness.submission;
  }

  testWidgets('save action triggers saveOnly export action', (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportSaveButton')),
    );

    expect(submission?.action, ExportAction.saveOnly);
  });

  testWidgets('share action triggers saveAndShare export action',
      (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportShareButton')),
    );

    expect(submission?.action, ExportAction.saveAndShare);
  });

  testWidgets('custom resolution export includes default dimensions',
      (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportSaveButton')),
      initialOptions: const ExportOptions(resolution: ExportResolution.custom),
    );

    expect(submission, isNotNull);
    expect(submission!.options.resolution, ExportResolution.custom);
    expect(submission.options.customWidth, 1920);
    expect(submission.options.customHeight, 1080);
  });

  testWidgets('custom fields remain export source after preset round-trip',
      (tester) async {
    tester.view.physicalSize = const Size(800, 1200);
    tester.view.devicePixelRatio = 1;
    addTearDown(tester.view.reset);

    final harness = await pumpSheet(
      tester,
      initialOptions: const ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 333,
        customHeight: 444,
      ),
    );

    await tester.tap(find.text('Customize').last);
    await tester.pumpAndSettle();

    await tester.tap(find.text('Web'));
    await tester.pumpAndSettle();

    await tester.tap(find.text(ExportResolution.custom.displayName));
    await tester.pumpAndSettle();

    expect(find.widgetWithText(TextField, '333'), findsOneWidget);
    expect(find.widgetWithText(TextField, '444'), findsOneWidget);

    await tester.tap(find.byKey(const ValueKey('exportSaveButton')));
    await tester.pumpAndSettle();

    expect(harness.submission, isNotNull);
    expect(harness.submission!.options.resolution, ExportResolution.custom);
    expect(harness.submission!.options.customWidth, 333);
    expect(harness.submission!.options.customHeight, 444);
  });

  testWidgets('sheet helper returns null when dismissed', (tester) async {
    ExportSheetSubmission? submission;

    await tester.pumpWidget(
      MaterialApp(
        locale: const Locale('en'),
        localizationsDelegates: AppLocalizations.localizationsDelegates,
        supportedLocales: AppLocalizations.supportedLocales,
        home: Scaffold(
          body: Builder(
            builder: (context) => Center(
              child: ElevatedButton(
                onPressed: () async {
                  submission = await ExportOptionsSheet.show(
                    context,
                    initialOptions: const ExportOptions(),
                    fractalType: 'mandelbrot',
                  );
                },
                child: const Text('Open'),
              ),
            ),
          ),
        ),
      ),
    );

    await tester.tap(find.text('Open'));
    await tester.pumpAndSettle();
    await tester.tapAt(const Offset(20, 20));
    await tester.pumpAndSettle();

    expect(submission, isNull);
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/export_options.dart';

void main() {
  group('ExportFormat', () {
    test('extension returns correct file extensions', () {
      expect(ExportFormat.png.extension, 'png');
      expect(ExportFormat.jpg.extension, 'jpg');
      expect(ExportFormat.webp.extension, 'webp');
    });

    test('mimeType returns correct MIME types', () {
      expect(ExportFormat.png.mimeType, 'image/png');
      expect(ExportFormat.jpg.mimeType, 'image/jpeg');
      expect(ExportFormat.webp.mimeType, 'image/webp');
    });
  });

  group('ExportResolution', () {
    test('dimensions returns correct values for preset resolutions', () {
      expect(ExportResolution.hd.dimensions, (1280, 720));
      expect(ExportResolution.fullHd.dimensions, (1920, 1080));
      expect(ExportResolution.quadHd.dimensions, (2560, 1440));
      expect(ExportResolution.uhd4k.dimensions, (3840, 2160));
      expect(ExportResolution.instagram.dimensions, (1080, 1080));
      expect(ExportResolution.instagramStory.dimensions, (1080, 1920));
      expect(ExportResolution.twitter.dimensions, (1200, 675));
    });

    test('screen and custom resolutions return null dimensions', () {
      expect(ExportResolution.screen.dimensions, isNull);
      expect(ExportResolution.custom.dimensions, isNull);
    });

    test('isSocialPreset identifies social presets correctly', () {
      expect(ExportResolution.instagram.isSocialPreset, isTrue);
      expect(ExportResolution.instagramStory.isSocialPreset, isTrue);
      expect(ExportResolution.twitter.isSocialPreset, isTrue);
      expect(ExportResolution.fullHd.isSocialPreset, isFalse);
      expect(ExportResolution.uhd4k.isSocialPreset, isFalse);
    });
  });

  group('ExportOptions', () {
    test('default options have sensible values', () {
      const options = ExportOptions();
      expect(options.format, ExportFormat.png);
      expect(options.resolution, ExportResolution.fullHd);
      expect(options.quality, 95);
      expect(options.embedMetadata, isTrue);
      expect(options.transparentBackground, isFalse);
    });

    test('calculatePixelRatio returns correct ratio for preset resolutions',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      // Portrait screen 400x800 -> Full HD adapts to 1080x1920.
      // Ratios: 1080/400 = 2.7, 1920/800 = 2.4 -> max = 2.7
      final ratio = options.calculatePixelRatio(400, 800);
      expect(ratio, closeTo(2.7, 0.1));
    });

    test('calculatePixelRatio is clamped to 8.0 max', () {
      const options = ExportOptions(resolution: ExportResolution.uhd4k);
      // Screen 100x100 -> would need 38.4 ratio, but clamped to 8
      final ratio = options.calculatePixelRatio(100, 100);
      expect(ratio, 8.0);
    });

    test('calculatePixelRatio sanitizes invalid screen dimensions for presets',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);

      expect(options.calculatePixelRatio(-400, -800), 8.0);
    });

    test('getTargetDimensions returns correct dimensions', () {
      const options = ExportOptions(resolution: ExportResolution.instagram);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1080));
    });

    test('getTargetDimensions adapts preset orientation to screen orientation',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1920));
    });

    test('social preset dimensions preserve platform crop contracts', () {
      const instagramStory = ExportOptions(
        resolution: ExportResolution.instagramStory,
      );
      const twitter = ExportOptions(resolution: ExportResolution.twitter);

      expect(instagramStory.getTargetDimensions(1200, 800), (1080, 1920));
      expect(twitter.getTargetDimensions(400, 800), (1200, 675));
      expect(
        instagramStory.calculatePixelRatio(1200, 800),
        closeTo(2.4, 0.01),
      );
    });

    test('custom resolution uses customWidth and customHeight', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (2000, 1500));
    });

    test('custom resolution ignores non-positive dimensions', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 0,
        customHeight: -10,
      );

      expect(options.getTargetDimensions(400, 800), (400, 800));
      expect(options.calculatePixelRatio(400, 800), 1.0);
    });

    test('custom resolution can fall back one axis at a time', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 0,
      );

      expect(options.getTargetDimensions(400, 800), (2000, 800));
      expect(options.calculatePixelRatio(400, 800), 5.0);
    });

    test('screen dimensions used for fallback are at least one pixel', () {
      const options = ExportOptions(resolution: ExportResolution.custom);

      expect(options.getTargetDimensions(0, -20), (1, 1));
      expect(options.calculatePixelRatio(0, -20), 1.0);
    });

    test('copyWith creates new instance with updated values', () {
      const original = ExportOptions();
      final updated = original.copyWith(
        format: ExportFormat.jpg,
        quality: 80,
      );

      expect(updated.format, ExportFormat.jpg);
      expect(updated.quality, 80);
      expect(updated.resolution, original.resolution); // Unchanged
    });

    test('copyWith clears nullable custom dimensions when null is explicit', () {
      const original = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );

      final updated = original.copyWith(
        customWidth: null,
        customHeight: null,
      );

      expect(updated.customWidth, isNull);
      expect(updated.customHeight, isNull);
      expect(updated.getTargetDimensions(400, 800), (400, 800));
    });

    test('copyWith clears nullable provenance fields when null is explicit',
        () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(
        metadata: null,
        watermarkText: null,
      );

      expect(updated.metadata, isNull);
      expect(updated.watermarkText, isNull);
    });

    test('copyWith omits nullable provenance fields without clearing them', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(quality: 80);

      expect(updated.metadata, same(metadata));
      expect(updated.watermarkText, 'Flutter Fractals');
    });
  });

  group('ExportMetadata', () {
    test('toExifMap returns expected keys', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );

      final exif = metadata.toExifMap();
      expect(exif, containsPair('Software', contains('Flutter Fractals')));
      expect(exif, containsPair('Artist', 'Flutter Fractals'));
      expect(exif, containsPair('UserComment', contains('mandelbrot')));
    });
  });

  group('ExportPresets', () {
    test('socialShare preset has correct settings', () {
      expect(ExportPresets.socialShare.format, ExportFormat.jpg);
      expect(ExportPresets.socialShare.resolution, ExportResolution.instagram);
      expect(ExportPresets.socialShare.quality, 90);
    });

    test('highQualityPng preset has correct settings', () {
      expect(ExportPresets.highQualityPng.format, ExportFormat.png);
      expect(ExportPresets.highQualityPng.resolution, ExportResolution.uhd4k);
    });

    test('webOptimized preset has correct settings', () {
      expect(ExportPresets.webOptimized.format, ExportFormat.webp);
      expect(ExportPresets.webOptimized.resolution, ExportResolution.fullHd);
      expect(ExportPresets.webOptimized.quality, 85);
    });

    test('transparentOverlay preset has correct settings', () {
      expect(ExportPresets.transparentOverlay.format, ExportFormat.png);
      expect(ExportPresets.transparentOverlay.transparentBackground, isTrue);
    });
  });
}

// Batch export service (generated by OpenClaw)
import 'dart:io';
import 'dart:typed_data';
import 'package:flutter/foundation.dart' show kDebugMode, kIsWeb;
import 'package:flutter/material.dart';
import 'package:image/image.dart' as img;
import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/services/export_service.dart';

class BatchExportItemResult {
  final FractalPreset preset;
  final File file;
  final int index;

  const BatchExportItemResult({
    required this.preset,
    required this.file,
    required this.index,
  });
}

class BatchExportResult {
  final Directory directory;
  final List<BatchExportItemResult> items;
  final File? contactSheet;

  const BatchExportResult({
    required this.directory,
    required this.items,
    this.contactSheet,
  });
}

/// Clock contract for replayable batch export directory naming.
abstract class BatchExportClock {
  DateTime now();
}

class SystemBatchExportClock implements BatchExportClock {
  const SystemBatchExportClock();

  @override
  DateTime now() => DateTime.now();
}

class BatchExportService {
  final ExportService _exportService;
  final BatchExportClock _clock;

  const BatchExportService({
    ExportService exportService = const ExportService(),
    BatchExportClock clock = const SystemBatchExportClock(),
  })  : _exportService = exportService,
        _clock = clock;

  Future<BatchExportResult> exportPresets({
    required GlobalKey boundaryKey,
    required Future<void> Function(FractalPreset preset) applyPreset,
    required List<FractalPreset> presets,
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    required String moduleId,
    required String moduleDisplayName,
    required Map<String, Object> Function() currentParameters,
    required void Function(double overallProgress, String status)? onProgress,
    required void Function(BatchExportItemResult item)? onItemDone,
    required bool Function() isCancelled,
  }) async {
    if (kIsWeb) throw UnsupportedError('exportPresets is not supported on web');
    final directory = await _createBatchDirectory(moduleId: moduleId);
    final results = <BatchExportItemResult>[];

    for (var i = 0; i < presets.length; i++) {
      if (isCancelled()) break;

      final preset = presets[i];
      onProgress?.call(i / presets.length,
          'Exporting ${i + 1}/${presets.length}: ${preset.name}');

      await applyPreset(preset);
      await WidgetsBinding.instance.endOfFrame;
      await WidgetsBinding.instance.endOfFrame;

      final metadata = options.embedMetadata
          ? ExportMetadata(
              title: preset.name,
              description: 'Preset export from $moduleDisplayName',
              fractalType: moduleId,
              parameters: Map<String, Object>.from(currentParameters()),
              createdAt: DateTime.now(),
            )
          : null;

      final bytes = await _exportService.captureWithOptions(
        boundaryKey,
        options: options.copyWith(metadata: metadata),
        screenWidth: screenWidth,
        screenHeight: screenHeight,
      );

      final filename = _presetFilename(
        moduleId: moduleId,
        index: i,
        presetName: preset.name,
        format: options.format,
      );
      final file = File('${directory.path}/$filename');
      await file.writeAsBytes(bytes, flush: true);

      final item = BatchExportItemResult(preset: preset, file: file, index: i);
      results.add(item);
      onItemDone?.call(item);
    }

    File? contactSheet;
    if (results.isNotEmpty && !isCancelled()) {
      onProgress?.call(0.95, 'Building contact sheet…');
      try {
        final pngBytes = await _buildContactSheet(
          results.map((e) => e.file).toList(),
          columns: 4,
          tileSize: 512,
          padding: 16,
        );
        final name = 'contact_sheet_${_safeSlug(moduleId)}.png';
        final out = File('${directory.path}/$name');
        await out.writeAsBytes(pngBytes, flush: true);
        contactSheet = out;
      } catch (e) {
        if (kDebugMode) debugPrint('[FF] silent catch: $e');
      }
    }

    onProgress?.call(1.0, 'Done');
    return BatchExportResult(
        directory: directory, items: results, contactSheet: contactSheet);
  }

  Future<Directory> _createBatchDirectory({required String moduleId}) async {
    final base = await _exportService.getExportDirectory();
    final ts = _clock.now();
    final stamp =
        '${ts.year.toString().padLeft(4, '0')}${ts.month.toString().padLeft(2, '0')}${ts.day.toString().padLeft(2, '0')}_${ts.hour.toString().padLeft(2, '0')}${ts.minute.toString().padLeft(2, '0')}${ts.second.toString().padLeft(2, '0')}';
    final prefix = '${base.path}/batch_${_safeSlug(moduleId)}_$stamp';

    for (var attempt = 1;; attempt++) {
      final suffix =
          attempt == 1 ? '' : '_${attempt.toString().padLeft(2, '0')}';
      final dir = Directory('$prefix$suffix');
      if (await dir.exists()) continue;
      await dir.create(recursive: true);
      return dir;
    }
  }

  String _presetFilename({
    required String moduleId,
    required int index,
    required String presetName,
    required ExportFormat format,
  }) {
    final idx = (index + 1).toString().padLeft(3, '0');
    final slug = _safeSlug(presetName);
    return '${_safeSlug(moduleId)}_${idx}_$slug.${format.extension}';
  }

  String _safeSlug(String input) {
    final trimmed = input.trim().toLowerCase();
    final replaced = trimmed
        .replaceAll(RegExp(r'[^a-z0-9]+'), '_')
        .replaceAll(RegExp(r'_+'), '_')
        .replaceAll(RegExp(r'^_'), '')
        .replaceAll(RegExp(r'_$'), '');
    return replaced.isEmpty ? 'untitled' : replaced;
  }

  Future<Uint8List> _buildContactSheet(
    List<File> files, {
    required int columns,
    required int tileSize,
    required int padding,
  }) async {
    final thumbs = <img.Image>[];
    for (final f in files) {
      final bytes = await f.readAsBytes();
      final decoded = img.decodeImage(bytes);
      if (decoded == null) continue;
      thumbs.add(img.copyResize(decoded,
          width: tileSize,
          height: tileSize,
          interpolation: img.Interpolation.cubic));
    }
    if (thumbs.isEmpty) throw StateError('No images');

    final cols = columns.clamp(1, 12);
    final rows = ((thumbs.length + cols - 1) / cols).floor();
    final width = padding + cols * (tileSize + padding);
    final height = padding + rows * (tileSize + padding);

    final sheet = img.Image(width: width, height: height, numChannels: 4);
    img.fill(sheet, color: img.ColorRgba8(12, 12, 12, 255));

    for (var i = 0; i < thumbs.length; i++) {
      final r = i ~/ cols;
      final c = i % cols;
      final x = padding + c * (tileSize + padding);
      final y = padding + r * (tileSize + padding);
      img.compositeImage(sheet, thumbs[i], dstX: x, dstY: y);
    }

    return Uint8List.fromList(img.encodePng(sheet, level: 6));
  }
}

// Tests for BatchExportService.
//
// Key constraint: exportPresets() calls WidgetsBinding.instance.endOfFrame
// for every preset that enters the loop body. That future only resolves when
// the Flutter test framework pumps a frame, which doesn't happen inside
// testWidgets/tester.runAsync reliably.
//
// Strategy:
//   - All exportPresets tests use plain test() with isCancelled:()=>true so
//     the loop guard fires before the body (and before endOfFrame is awaited).
//   - The empty-presets path also never reaches endOfFrame.
//   - Value-type tests (BatchExportItemResult, BatchExportResult, ExportOptions)
//     are pure synchronous tests.
import 'dart:io';
import 'dart:typed_data';
import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:path_provider_platform_interface/path_provider_platform_interface.dart';
import 'package:plugin_platform_interface/plugin_platform_interface.dart';
import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/services/batch_export_service.dart';
import 'package:flutter_fractals/core/services/export_service.dart';
